class Solution {
public:
    int countPalindromicSubsequences(string S) {
        const int MOD = 1e9+7;
        int n=S.size();
        vector<vector<long long>> dp(n, vector<long long>(n));
        for(int i=0;i<n;i++) dp[i][i]=1;
        for(int len=2;len<=n;len++) for(int l=0;l+len-1<n;l++){
            int r=l+len-1;
            if(S[l]==S[r]){
                dp[l][r]=dp[l+1][r-1]*2+2;
                int i=l+1,j=r-1;
                while(i<=j&&S[i]!=S[l]) i++;
                while(i<=j&&S[j]!=S[l]) j--;
                if(i>j) dp[l][r]--;
                else if(i==j) dp[l][r]--;
                else dp[l][r]-=2;
            } else dp[l][r]=(dp[l+1][r]+dp[l][r-1]-dp[l+1][r-1]+MOD)%MOD;
            dp[l][r]%=MOD;
        }
        return dp[0][n-1];
    }
};

